import React from "react";
import { Box, Typography } from "@mui/material";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import usecatagories from "../../hooks/usecatagories";

// صور مخصصة لكل كاتيجوري
const categoryImages = {
  Mobiles:
    "https://images.unsplash.com/photo-1511707171634-5f897ff02aa9?w=800",
  Clothes:
    "https://th.bing.com/th/id/OIP.dy95VE-wxNp6Yh7RAyBhpwHaE8?w=294&h=196&c=7&r=0&o=7&cb=defcachec2&dpr=1.3&pid=1.7&rm=3",
  Electronics:
    "https://th.bing.com/th/id/OIP.goBFTF8nYkUun1eRBMWewQHaE8?w=314&h=180&c=7&r=0&o=7&cb=defcachec2&dpr=1.3&pid=1.7&rm=3",
  Shoes:
    "https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=800",
  Accessories:
    "https://images.unsplash.com/photo-1611652022419-a9419f74343d?w=800",
  "Home Appliances":
    "https://th.bing.com/th/id/OIP.xj1dZZPfMune7B03uhHiQAHaE8?w=261&h=180&c=7&r=0&o=7&cb=defcachec2&dpr=1.3&pid=1.7&rm=3",
  "Beauty Products":
    "https://images.unsplash.com/photo-1596462502278-27bfdc403348?w=800",
  cat9:
    "data:image/webp;base64,",
};

export default function Categories() {
  const { data, isLoading, isError } = usecatagories();

  if (isLoading) return <div>Loading categories...</div>;
  if (isError) return <div>Error loading categories</div>;

  const categoriesArray = data?.response || [];

  return (
    <Box sx={{ py: 6, px: { xs: 2, md: 6 }, backgroundColor: "#fafafa" }}>
      <Typography
        variant="h4"
        fontWeight={800}
        mb={4}
        textAlign="center"
      >
        Our Categories
      </Typography>

      <Swiper
        slidesPerView={1}
        spaceBetween={20}
        loop={true}
        breakpoints={{
          600: { slidesPerView: 2 },
          900: { slidesPerView: 3 },
          1200: { slidesPerView: 4 },
        }}
      >
        {categoriesArray.map((cat) => (
          <SwiperSlide key={cat.id}>
            <Box
              sx={{
                position: "relative",
                height: 260,
                borderRadius: "20px",
                overflow: "hidden",
                cursor: "pointer",
                transition: "0.4s",
                boxShadow: 3,
                "&:hover img": {
                  transform: "scale(1.1)",
                },
                "&:hover .overlay": {
                  backgroundColor: "rgba(0,0,0,0.5)",
                },
              }}
            >
              <img
                src={
                  categoryImages[cat.name] ||
                  "https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=800"
                }
                alt={cat.name}
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover",
                  transition: "0.4s",
                }}
              />

              <Box
                className="overlay"
                sx={{
                  position: "absolute",
                  inset: 0,
                  backgroundColor: "rgba(0,0,0,0.35)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  transition: "0.4s",
                }}
              >
                <Typography
                  variant="h5"
                  fontWeight={700}
                  color="#fff"
                  textAlign="center"
                >
                  {cat.name}
                </Typography>
              </Box>
            </Box>
          </SwiperSlide>
        ))}
      </Swiper>
    </Box>
  );
}
